15	// validEntityTypes is the closed set of entity types that may carry custom fields.
16	var validEntityTypes = map[string]bool{
17		"user":     true,
18		"course":   true,
19		"material": true,
20		"location": true,
21	}
22	
23	// extractEntityParams resolves entity_type and entity_id from the request URL.
24	// It supports both the generic routes (/admin/fields/:entity_type/:entity_id)
25	// and the legacy user-scoped routes (/admin/users/:id/fields).
26	// Returns an error when entity_type is not in validEntityTypes or entity_id is
27	// not a valid integer.
28	func extractEntityParams(c *fiber.Ctx) (entityType string, entityID int64, err error) {
29		entityType = c.Params("entity_type")
30		if entityType == "" {
31			entityType = "user" // legacy route: /admin/users/:id/fields
32		}
33		if !validEntityTypes[entityType] {
34			return "", 0, errors.New("invalid entity type: must be user, course, material, or location")
35		}
36		idStr := c.Params("entity_id")
37		if idStr == "" {
38			idStr = c.Params("id") // legacy route param name
39		}
40		id, parseErr := strconv.ParseInt(idStr, 10, 64)
41		if parseErr != nil || id <= 0 {
42			return "", 0, errors.New("invalid entity ID")
43		}
44		return entityType, id, nil
45	}
