47	// AdminHandler serves all admin UI routes: user management, custom fields,
48	// duplicate detection, merging, and audit log.
49	type AdminHandler struct {
50		adminService *services.AdminService
51		authService  *services.AuthService
52	}
53	
54	// NewAdminHandler creates an AdminHandler backed by the given services.
55	func NewAdminHandler(as *services.AdminService, aus *services.AuthService) *AdminHandler {
56		return &AdminHandler{adminService: as, authService: aus}
57	}
