63	// ListUsers handles GET /admin/users — paginated user list with optional role filter.
64	func (h *AdminHandler) ListUsers(c *fiber.Ctx) error {
65		role := c.Query("role")
66		page := c.QueryInt("page", 1)
67		if page < 1 {
68			page = 1
69		}
70		limit := 50
71		offset := (page - 1) * limit
72	
73		users, err := h.adminService.ListUsers(role, limit, offset)
74		if err != nil {
75			observability.App.Warn("list users failed", "role_filter", role, "error", err)
76			users = nil
77		}
78	
79		return c.Render("admin/users/list", fiber.Map{
80			"Title":      "User Management",
81			"User":       middleware.GetUser(c),
82			"Users":      users,
83			"RoleFilter": role,
84			"Page":       page,
85		}, "layouts/main")
86	}
