88	// NewUserForm handles GET /admin/users/new.
89	func (h *AdminHandler) NewUserForm(c *fiber.Ctx) error {
90		return c.Render("admin/users/new", fiber.Map{
91			"Title": "Create User",
92			"User":  middleware.GetUser(c),
93		}, "layouts/main")
94	}
