96	// CreateUser handles POST /admin/users.
97	func (h *AdminHandler) CreateUser(c *fiber.Ctx) error {
98		username := c.FormValue("username")
99		email := c.FormValue("email")
100		password := c.FormValue("password")
101		role := c.FormValue("role")
102		fullName := c.FormValue("full_name")
103		if role == "" {
104			role = "student"
105		}
106	
107		user, err := h.adminService.CreateUser(username, email, password, role, fullName, encKeyFromContext(c))
108		if err != nil {
109			observability.App.Warn("create user rejected", "username", username, "role", role, "error", err)
110			return c.Status(fiber.StatusUnprocessableEntity).Render("admin/users/new", fiber.Map{
111				"Title": "Create User",
112				"Error": "Could not create user. Please check your input and try again.",
113				"User":  middleware.GetUser(c),
114			}, "layouts/main")
115		}
116	
117		return c.Redirect("/admin/users/"+strconv.FormatInt(user.ID, 10), fiber.StatusFound)
118	}
