124	// UserProfile handles GET /admin/users/:id.
125	func (h *AdminHandler) UserProfile(c *fiber.Ctx) error {
126		id, err := c.ParamsInt("id")
127		if err != nil {
128			return apiErr(c, fiber.StatusBadRequest, "Invalid user ID")
129		}
130	
131		encKey := encKeyFromContext(c)
132		fields, err := h.adminService.GetCustomFields("user", int64(id), encKey)
133		if err != nil {
134			observability.App.Warn("get custom fields failed", "target_user_id", id, "error", err)
135			fields = nil
136		}
137		auditLog, err := h.adminService.GetAuditLog("user", int64(id), 20, 0)
138		if err != nil {
139			observability.App.Warn("get audit log failed", "target_user_id", id, "error", err)
140			auditLog = nil
141		}
142	
143		// Fetch the target user via ListUsers with a high limit and find by ID.
144		// (We reuse the admin repo path; a direct GetByID is available via userRepo
145		//  but the admin handler only holds adminService. We call ListUsers offset=0
146		//  and search — simpler: expose userRepo.GetByID in adminService.)
147		users, err := h.adminService.ListUsers("", 10000, 0)
148		if err != nil {
149			observability.App.Warn("list users for profile failed", "target_user_id", id, "error", err)
150			users = nil
151		}
152		var targetUser interface{}
153		for i := range users {
154			if users[i].ID == int64(id) {
155				// Decrypt sensitive fields before rendering so the admin sees plaintext.
156				decrypted := h.adminService.DecryptUser(&users[i], encKey)
157				targetUser = decrypted
158				break
159			}
160		}
161	
162		displayName := h.adminService.GetEntityDisplayName("user", int64(id))
163	
164		return c.Render("admin/users/profile", fiber.Map{
165			"Title":             "User Profile — " + displayName,
166			"User":              middleware.GetUser(c),
167			"EntityType":        "user",
168			"EntityDisplayName": displayName,
169			"TargetID":          int64(id),
170			"TargetUser":        targetUser,
171			"Fields":            fields,
172			"AuditLog":          auditLog,
173		}, "layouts/main")
174	}
