176	// UpdateRole handles POST /admin/users/:id/role.
177	func (h *AdminHandler) UpdateRole(c *fiber.Ctx) error {
178		id, err := c.ParamsInt("id")
179		if err != nil {
180			return apiErr(c, fiber.StatusBadRequest, "Invalid user ID")
181		}
182		role := c.FormValue("role")
183		actor := middleware.GetUser(c)
184	
185		if err := h.adminService.UpdateUserRole(int64(id), role, actor.ID, c.IP()); err != nil {
186			return htmxErr(c, fiber.StatusUnprocessableEntity, "Could not update role. Please try again.")
187		}
188	
189		observability.Security.Info("user role changed",
190			"target_user_id", id, "new_role", role,
191			"actor_id", actor.ID, "actor_ip", c.IP())
192	
193		if c.Get("HX-Request") == "true" {
194			return c.Render("partials/flash", fiber.Map{"Message": "Role updated."})
195		}
196		return c.Redirect("/admin/users/"+strconv.Itoa(id), fiber.StatusFound)
197	}
