199	// UnlockUser handles POST /admin/users/:id/unlock.
200	func (h *AdminHandler) UnlockUser(c *fiber.Ctx) error {
201		id, err := c.ParamsInt("id")
202		if err != nil {
203			return apiErr(c, fiber.StatusBadRequest, "Invalid user ID")
204		}
205		actor := middleware.GetUser(c)
206	
207		if err := h.adminService.UnlockUser(int64(id), actor.ID); err != nil {
208			return htmxErr(c, fiber.StatusUnprocessableEntity, "Could not unlock account. Please try again.")
209		}
210	
211		observability.Security.Info("account unlocked",
212			"target_user_id", id,
213			"actor_id", actor.ID, "actor_ip", c.IP())
214	
215		if c.Get("HX-Request") == "true" {
216			return c.Render("partials/flash", fiber.Map{"Message": "Account unlocked."})
217		}
218		return c.Redirect("/admin/users/"+strconv.Itoa(id), fiber.StatusFound)
219	}
