253	// SetCustomField handles POST /admin/fields/:entity_type/:entity_id
254	// and the legacy POST /admin/users/:id/fields.
255	func (h *AdminHandler) SetCustomField(c *fiber.Ctx) error {
256		entityType, entityID, err := extractEntityParams(c)
257		if err != nil {
258			return apiErr(c, fiber.StatusBadRequest, err.Error())
259		}
260	
261		name := c.FormValue("field_name")
262		value := c.FormValue("field_value")
263		encrypt := c.FormValue("encrypt") == "true" || c.FormValue("encrypt") == "1"
264	
265		encKey := encKeyFromContext(c)
266		if err := h.adminService.SetCustomField(entityType, entityID, name, value, encrypt, encKey); err != nil {
267			return htmxErr(c, fiber.StatusUnprocessableEntity, "Could not save field. Please try again.")
268		}
269	
270		if c.Get("HX-Request") == "true" {
271			return c.Render("partials/flash", fiber.Map{"Message": "Field saved."})
272		}
273		return c.Redirect(
274			"/admin/fields/"+entityType+"/"+strconv.FormatInt(entityID, 10),
275			fiber.StatusFound,
276		)
277	}
