305	// DuplicatesPage handles GET /admin/duplicates.
306	func (h *AdminHandler) DuplicatesPage(c *fiber.Ctx) error {
307		pairs, err := h.adminService.FindDuplicates()
308		if err != nil {
309			observability.App.Warn("find duplicates failed", "error", err)
310			pairs = nil
311		}
312	
313		mergeHistory, err := h.adminService.GetAuditLog("user", 0, 20, 0)
314		if err != nil {
315			observability.App.Warn("get merge history failed", "error", err)
316			mergeHistory = nil
317		}
318	
319		return c.Render("admin/duplicates", fiber.Map{
320			"Title":        "Duplicate Users",
321			"User":         middleware.GetUser(c),
322			"Pairs":        pairs,
323			"MergeHistory": mergeHistory,
324		}, "layouts/main")
325	}
