327	// MergeUsers handles POST /admin/duplicates/merge.
328	func (h *AdminHandler) MergeUsers(c *fiber.Ctx) error {
329		primaryIDStr := c.FormValue("primary_id")
330		duplicateIDStr := c.FormValue("duplicate_id")
331	
332		primaryID, err := strconv.ParseInt(primaryIDStr, 10, 64)
333		if err != nil || primaryID <= 0 {
334			return apiErr(c, fiber.StatusBadRequest, "Invalid primary user ID")
335		}
336		duplicateID, err := strconv.ParseInt(duplicateIDStr, 10, 64)
337		if err != nil || duplicateID <= 0 {
338			return apiErr(c, fiber.StatusBadRequest, "Invalid duplicate user ID")
339		}
340		if primaryID == duplicateID {
341			return apiErr(c, fiber.StatusBadRequest, "Primary and duplicate must be different users")
342		}
343	
344		actor := middleware.GetUser(c)
345		if err := h.adminService.MergeUsers(primaryID, duplicateID, actor.ID); err != nil {
346			return internalErr(c, observability.App, "merge users failed", err,
347				"primary_id", primaryID, "duplicate_id", duplicateID, "actor_id", actor.ID)
348		}
349	
350		observability.Security.Warn("users merged",
351			"primary_id", primaryID, "duplicate_id", duplicateID, "actor_id", actor.ID)
352	
353		if c.Get("HX-Request") == "true" {
354			return c.Render("partials/flash", fiber.Map{
355				"Message": "Users merged successfully.",
356			})
357		}
358		return c.Redirect("/admin/duplicates", fiber.StatusFound)
359	}
