1	package services
2	
3	import (
4		"fmt"
5	
6		"w2t86/internal/crypto"
7		"w2t86/internal/models"
8		"w2t86/internal/observability"
9		"w2t86/internal/repository"
10	)
11	
12	// AdminService orchestrates admin-level operations: user management,
13	// custom fields, duplicate detection / merging, and audit log access.
14	type AdminService struct {
15		adminRepo    *repository.AdminRepository
16		userRepo     *repository.UserRepository
17		materialRepo *repository.MaterialRepository
18	}
19	
20	// NewAdminService creates an AdminService wired to the given repositories.
21	func NewAdminService(
22		ar *repository.AdminRepository,
23		ur *repository.UserRepository,
24		mr *repository.MaterialRepository,
25	) *AdminService {
26		return &AdminService{adminRepo: ar, userRepo: ur, materialRepo: mr}
27	}
28	
29	// ---------------------------------------------------------------
30	// User admin
31	// ---------------------------------------------------------------
32	
33	// ListUsers returns paginated users optionally filtered by role.
34	func (s *AdminService) ListUsers(role string, limit, offset int) ([]models.User, error) {
35		return s.adminRepo.ListUsers(role, limit, offset)
36	}
37	
38	// CreateUser registers a new user account.  fullName is the person's real
39	// name used for duplicate detection; pass an empty string to leave it unset.
40	// encKey, if 32 bytes, encrypts fullName before storage.
41	func (s *AdminService) CreateUser(username, email, password, role, fullName string, encKey []byte) (*models.User, error) {
42		authSvc := &AuthService{userRepo: s.userRepo}
43		user, err := authSvc.Register(username, email, password, role)
44		if err != nil {
45			return nil, fmt.Errorf("service: AdminService.CreateUser: %w", err)
46		}
47		if fullName != "" {
48			stored, err := encryptSensitiveField(encKey, fullName)
49			if err != nil {
50				return nil, fmt.Errorf("service: AdminService.CreateUser: encrypt full_name: %w", err)
51			}
52			idx := crypto.BlindIndex(encKey, fullName)
53			if err := s.userRepo.SetFullName(user.ID, stored, idx); err != nil {
54				// Non-fatal: user was created; log and continue.
55				observability.App.Warn("set full_name failed", "user_id", user.ID, "error", err)
56			} else {
57				user.FullName = &fullName // expose plaintext to caller
58			}
59		}
60		return user, nil
61	}
62	
63	// SetUserFullName encrypts fullName and stores the value along with its HMAC
64	// blind index.  encKey must be exactly 32 bytes; the call fails if it is not.
65	func (s *AdminService) SetUserFullName(userID int64, fullName string, encKey []byte) error {
66		stored, err := encryptSensitiveField(encKey, fullName)
67		if err != nil {
68			return fmt.Errorf("service: AdminService.SetUserFullName: %w", err)
69		}
70		idx := crypto.BlindIndex(encKey, fullName)
71		return s.userRepo.SetFullName(userID, stored, idx)
72	}
73	
74	// SetUserExternalID encrypts externalID and stores the value along with its HMAC
75	// blind index.  encKey must be exactly 32 bytes; the call fails if it is not.
76	func (s *AdminService) SetUserExternalID(userID int64, externalID string, encKey []byte) error {
77		stored, err := encryptSensitiveField(encKey, externalID)
78		if err != nil {
79			return fmt.Errorf("service: AdminService.SetUserExternalID: %w", err)
80		}
81		idx := crypto.BlindIndex(encKey, externalID)
82		return s.userRepo.SetExternalID(userID, stored, idx)
83	}
84	
85	// DecryptUser decrypts the sensitive fields (full_name, external_id,
86	// date_of_birth) on a copy of the user.  If a field is not encrypted (legacy
87	// plaintext row) or decryption fails, the stored value is returned as-is.
88	func (s *AdminService) DecryptUser(user *models.User, encKey []byte) *models.User {
89		if user == nil {
90			return nil
91		}
92		out := *user // shallow copy — only pointer fields differ
93		if user.FullName != nil {
94			plain := decryptSensitiveField(encKey, *user.FullName)
95			out.FullName = &plain
96		}
97		if user.ExternalID != nil {
98			plain := decryptSensitiveField(encKey, *user.ExternalID)
99			out.ExternalID = &plain
100		}
101		if user.DateOfBirth != nil {
102			plain := decryptSensitiveField(encKey, *user.DateOfBirth)
103			out.DateOfBirth = &plain
104		}
105		return &out
106	}
