415	// encKeyFromContext derives the 32-byte AES key from the session user context.
416	// In a real deployment the key would come from the server config; here we
417	// decode the hex string that was loaded into the Fiber app's Locals during
418	// startup (set by main.go as "enc_key").
419	func encKeyFromContext(c *fiber.Ctx) []byte {
420		raw, _ := c.Locals("enc_key").(string)
421		if raw == "" {
422			return nil
423		}
424		key, err := hex.DecodeString(raw)
425		if err != nil || len(key) != 32 {
426			return nil
427		}
428		return key
429	}
