226	// geoJSONFeature is the internal representation of a GeoJSON Feature.
227	type geoJSONFeature struct {
228		Type     string                 `json:"type"`
229		Geometry geoJSONGeometry        `json:"geometry"`
230		Props    map[string]interface{} `json:"properties"`
231	}
232	
233	type geoJSONGeometry struct {
234		Type        string    `json:"type"`
235		Coordinates []float64 `json:"coordinates"`
236	}
237	
238	type geoJSONCollection struct {
239		Type     string           `json:"type"`
240		Features []geoJSONFeature `json:"features"`
241	}
242	
243	// locationsToGeoJSON converts a slice of Location rows into a GeoJSON
244	// FeatureCollection string.  Locations without lat/lng are skipped.
245	func locationsToGeoJSON(locations []models.Location) string {
246		features := make([]geoJSONFeature, 0, len(locations))
247		for _, loc := range locations {
248			if loc.Lat == nil || loc.Lng == nil {
249				continue
250			}
251			props := map[string]interface{}{
252				"id":   loc.ID,
253				"name": loc.Name,
254			}
255			if loc.Type != nil {
256				props["type"] = *loc.Type
257			}
258			if loc.Properties != nil {
259				// Attempt to merge the stored JSON properties blob.
260				var extra map[string]interface{}
261				if err := json.Unmarshal([]byte(*loc.Properties), &extra); err == nil {
262					for k, v := range extra {
263						props[k] = v
264					}
265				} else {
266					props["properties"] = *loc.Properties
267				}
268			}
269			features = append(features, geoJSONFeature{
270				Type: "Feature",
271				Geometry: geoJSONGeometry{
272					Type:        "Point",
273					Coordinates: []float64{*loc.Lng, *loc.Lat}, // GeoJSON order: [lng, lat]
274				},
275				Props: props,
276			})
277		}
278	
279		col := geoJSONCollection{
280			Type:     "FeatureCollection",
281			Features: features,
282		}
283		b, err := json.Marshal(col)
284		if err != nil {
285			return `{"type":"FeatureCollection","features":[]}`
286		}
287		return string(b)
288	}
