353	// GetLocations returns all locations of the given type.  Pass "" to return all.
354	func (r *AnalyticsRepository) GetLocations(locType string) ([]models.Location, error) {
355		q := `SELECT id, name, type, geom_wkt, lat, lng, properties, created_at FROM locations`
356		args := []interface{}{}
357		if locType != "" {
358			q += ` WHERE type = ?`
359			args = append(args, locType)
360		}
361		q += ` ORDER BY name`
362	
363		rows, err := r.db.Query(q, args...)
364		if err != nil {
365			return nil, fmt.Errorf("analytics: GetLocations: %w", err)
366		}
367		defer rows.Close()
368	
369		var out []models.Location
370		for rows.Next() {
371			var l models.Location
372			if err := rows.Scan(&l.ID, &l.Name, &l.Type, &l.GeomWKT, &l.Lat, &l.Lng, &l.Properties, &l.CreatedAt); err != nil {
373				return nil, fmt.Errorf("analytics: GetLocations scan: %w", err)
374			}
375			out = append(out, l)
376		}
377		return out, rows.Err()
378	}
