143	// UpdateUserRole changes a user's role and writes an audit log entry.
144	func (s *AdminService) UpdateUserRole(userID int64, role string, actorID int64, actorIP string) error {
145		// Capture before state.
146		before, _ := s.userRepo.GetByID(userID)
147	
148		if err := s.adminRepo.UpdateUserRole(userID, role); err != nil {
149			return fmt.Errorf("service: AdminService.UpdateUserRole: %w", err)
150		}
151	
152		// Write audit log (best-effort).
153		after, _ := s.userRepo.GetByID(userID)
154		_ = s.adminRepo.WriteAuditLog(actorID, "update_role", "user", userID, before, after, actorIP)
155		observability.Security.Info("role changed", "target_user_id", userID, "new_role", role, "actor_id", actorID)
156		return nil
157	}
