159	// UnlockUser clears a user's account lockout.
160	func (s *AdminService) UnlockUser(userID int64, actorID int64) error {
161		if err := s.adminRepo.UnlockUser(userID); err != nil {
162			return fmt.Errorf("service: AdminService.UnlockUser: %w", err)
163		}
164		_ = s.adminRepo.WriteAuditLog(actorID, "unlock", "user", userID, nil, nil, "")
165		observability.Security.Info("account unlocked", "target_user_id", userID, "actor_id", actorID)
166		return nil
167	}
168	
169	// SetCustomField stores a custom field for the given entity.
170	// If encrypt is true the value is AES-256-GCM encrypted with encKey before
171	// being stored; encKey must be exactly 32 bytes.  If encryption is requested
172	// but the key is absent or the wrong length, the call fails rather than
173	// silently falling back to plaintext storage.
174	func (s *AdminService) SetCustomField(entityType string, entityID int64, name, value string, encrypt bool, encKey []byte) error {
175		stored := value
176		if encrypt {
177			if len(encKey) != 32 {
178				return fmt.Errorf("service: AdminService.SetCustomField: encryption requested but key is invalid or missing (got %d bytes, need 32)", len(encKey))
179			}
180			enc, err := crypto.EncryptField(encKey, value)
181			if err != nil {
182				return fmt.Errorf("service: AdminService.SetCustomField: encrypt: %w", err)
183			}
184			stored = enc
185		}
186		return s.adminRepo.SetCustomField(entityType, entityID, name, stored, encrypt)
187	}
188	
189	// GetCustomFields returns all custom fields for the given entity.
190	// Encrypted fields have their FieldValue replaced with the plaintext if encKey
191	// is provided and 32 bytes; otherwise the raw (ciphertext) value is returned.
192	func (s *AdminService) GetCustomFields(entityType string, entityID int64, encKey []byte) ([]models.EntityCustomField, error) {
193		fields, err := s.adminRepo.GetCustomFields(entityType, entityID)
194		if err != nil {
195			return nil, err
196		}
197		if len(encKey) == 32 {
198			for i, f := range fields {
199				if f.IsEncrypted == 1 && f.FieldValue != nil {
200					plain, decErr := crypto.DecryptField(encKey, *f.FieldValue)
201					if decErr == nil {
202						fields[i].FieldValue = &plain
203					}
204					// If decryption fails leave the raw value; caller can decide.
205				}
206			}
207		}
208		return fields, nil
209	}
210	
211	// DeleteCustomField removes a custom field for the given entity.
212	func (s *AdminService) DeleteCustomField(entityType string, entityID int64, name string) error {
213		return s.adminRepo.DeleteCustomField(entityType, entityID, name)
214	}
215	
216	// GetEntityDisplayName returns a human-readable label for the entity
217	// (e.g. the user's username, a material's title, a course name).
218	// Never returns an error; falls back to "<type> #<id>" for unknown rows.
219	func (s *AdminService) GetEntityDisplayName(entityType string, entityID int64) string {
220		return s.adminRepo.GetEntityDisplayName(entityType, entityID)
221	}
