233	func (s *AdminService) MergeUsers(primaryID, duplicateID int64, actorID int64) error {
234		if err := s.adminRepo.MergeUsers(primaryID, duplicateID, actorID); err != nil {
235			return fmt.Errorf("service: AdminService.MergeUsers: %w", err)
236		}
237		_ = s.adminRepo.WriteAuditLog(actorID, "merge_user", "user", primaryID,
