15	// OrderHandler handles all order-lifecycle HTTP routes for both student and
16	// admin/clerk users.
17	type OrderHandler struct {
18		orderService *services.OrderService
19	}
20	
21	// NewOrderHandler creates an OrderHandler backed by the given service.
22	func NewOrderHandler(os *services.OrderService) *OrderHandler {
23		return &OrderHandler{orderService: os}
24	}
25	
26	// ---------------------------------------------------------------
27	// Student routes
28	// ---------------------------------------------------------------
29	
30	// ListOrders handles GET /orders — renders the authenticated user's order list.
31	func (h *OrderHandler) ListOrders(c *fiber.Ctx) error {
32		user := middleware.GetUser(c)
33	
34		limit := 20
35		offset := 0
36		if p := c.QueryInt("page", 1); p > 1 {
37			offset = (p - 1) * limit
38		}
39	
40		orders, err := h.orderService.GetOrdersForUser(user.ID, limit, offset)
41		if err != nil {
42			return internalErr(c, observability.Orders, "get orders for user failed", err, "user_id", user.ID)
43		}
44	
45		return c.Render("orders/list", fiber.Map{
46			"Title":      "My Orders",
47			"User":       user,
48			"Orders":     orders,
49			"ActivePage": "orders",
50		}, "layouts/base")
51	}
52	
53	// OrderDetail handles GET /orders/:id — renders the full order detail page.
54	func (h *OrderHandler) OrderDetail(c *fiber.Ctx) error {
55		id, err := c.ParamsInt("id")
56		if err != nil {
57			return apiErr(c, fiber.StatusBadRequest, "Invalid order ID")
58		}
59	
60		user := middleware.GetUser(c)
61	
62		order, items, err := h.orderService.GetOrderByID(int64(id))
63		if err != nil {
64			return apiErr(c, fiber.StatusNotFound, "Order not found")
65		}
66	
67		// Enforce explicit allowlist: the order owner may always view their own
68		// order; admin, instructor, and clerk have operational need-to-know.
69		// All other roles (e.g. moderator) are denied.
70		switch user.Role {
71		case "admin", "instructor", "clerk":
72			// Permitted — these roles have operational need-to-know for order details.
73		case "student":
74			if order.UserID != user.ID {
75				observability.Security.Warn("unauthorized order access attempt",
76					"user_id", user.ID, "order_id", id, "order_owner_id", order.UserID, "ip", c.IP())
77				return apiErr(c, fiber.StatusForbidden, "You do not have permission to perform this action")
78			}
79		default:
80			observability.Security.Warn("unauthorized order access attempt by non-student role",
81				"user_id", user.ID, "role", user.Role, "order_id", id, "ip", c.IP())
82			return apiErr(c, fiber.StatusForbidden, "You do not have permission to perform this action")
83		}
84	
85		events, err := h.orderService.GetOrderEvents(int64(id))
86		if err != nil {
87			observability.Orders.Warn("get order events failed", "order_id", id, "error", err)
88			events = nil
