114	// PlaceOrder handles POST /orders — places an order from the submitted cart form.
115	func (h *OrderHandler) PlaceOrder(c *fiber.Ctx) error {
116		user := middleware.GetUser(c)
117	
118		// Parse multi-value form fields: material_id[] and qty[] and unit_price[].
119		materialIDs := c.Request().PostArgs().PeekMulti("material_id")
120		qtys := c.Request().PostArgs().PeekMulti("qty")
121		prices := c.Request().PostArgs().PeekMulti("unit_price")
122	
123		if len(materialIDs) == 0 || len(materialIDs) != len(qtys) {
124			return htmxErr(c, fiber.StatusBadRequest, "Invalid cart data")
125		}
126	
127		items := make([]repository.OrderItemInput, 0, len(materialIDs))
128		for i, rawID := range materialIDs {
129			mid, err := strconv.ParseInt(string(rawID), 10, 64)
130			if err != nil {
131				return htmxErr(c, fiber.StatusBadRequest, "Invalid material ID in cart")
132			}
133			qty, err := strconv.Atoi(string(qtys[i]))
134			if err != nil || qty <= 0 {
135				return htmxErr(c, fiber.StatusBadRequest, "Invalid quantity in cart")
136			}
137			var unitPrice float64
138			if i < len(prices) {
139				unitPrice, _ = strconv.ParseFloat(string(prices[i]), 64)
140			}
141			items = append(items, repository.OrderItemInput{
142				MaterialID: mid,
143				Qty:        qty,
144				UnitPrice:  unitPrice,
145			})
146		}
147	
148		order, err := h.orderService.PlaceOrder(user.ID, items)
149		if err != nil {
150			observability.Orders.Warn("place order rejected", "user_id", user.ID, "error", err)
151			errData := fiber.Map{
152				"Title": "Checkout",
153				"User":  user,
154				"Error": "Could not place your order. Please check your cart and try again.",
155			}
156			if c.Get("HX-Request") == "true" {
157				return c.Status(fiber.StatusUnprocessableEntity).Render("orders/cart", errData)
158			}
159			return c.Status(fiber.StatusUnprocessableEntity).Render("orders/cart", errData, "layouts/base")
160		}
161	
162		observability.Orders.Info("order placed by user", "order_id", order.ID, "user_id", user.ID)
163		return c.Redirect(fmt.Sprintf("/orders/%d", order.ID), fiber.StatusFound)
164	}
