1	package services
2	
3	import (
4		"database/sql"
5		"errors"
6		"fmt"
7	
8		"w2t86/internal/models"
9		"w2t86/internal/observability"
10		"w2t86/internal/repository"
11	)
12	
13	// OrderService orchestrates all order-lifecycle, return, and inventory operations.
14	type OrderService struct {
15		orderRepo    *repository.OrderRepository
16		materialRepo *repository.MaterialRepository
17	}
18	
19	// NewOrderService creates an OrderService wired to the given repositories.
20	func NewOrderService(or *repository.OrderRepository, mr *repository.MaterialRepository) *OrderService {
21		return &OrderService{orderRepo: or, materialRepo: mr}
22	}
23	
24	// ---------------------------------------------------------------
25	// Order placement
26	// ---------------------------------------------------------------
27	
28	// PlaceOrder validates that every requested material exists and has sufficient
29	// stock, then delegates to OrderRepository.Create.
30	func (s *OrderService) PlaceOrder(userID int64, items []repository.OrderItemInput) (*models.Order, error) {
31		if len(items) == 0 {
32			return nil, errors.New("service: PlaceOrder: cart is empty")
33		}
34	
35		for _, it := range items {
36			if it.Qty <= 0 {
37				return nil, fmt.Errorf("service: PlaceOrder: quantity must be positive for material %d", it.MaterialID)
38			}
39			mat, err := s.materialRepo.GetByID(it.MaterialID)
40			if err != nil {
41				if errors.Is(err, sql.ErrNoRows) {
42					return nil, fmt.Errorf("service: PlaceOrder: material %d not found", it.MaterialID)
43				}
44				return nil, fmt.Errorf("service: PlaceOrder: fetch material %d: %w", it.MaterialID, err)
45			}
46			if mat.Status != "active" {
47				return nil, fmt.Errorf("service: PlaceOrder: material %q is not available for ordering", mat.Title)
48			}
49			if mat.AvailableQty < it.Qty {
50				return nil, fmt.Errorf("service: PlaceOrder: insufficient stock for %q (available: %d, requested: %d)",
51					mat.Title, mat.AvailableQty, it.Qty)
52			}
53		}
54	
55		order, err := s.orderRepo.Create(userID, items)
56		if err != nil {
57			return nil, fmt.Errorf("service: PlaceOrder: %w", err)
58		}
59	
60		observability.Orders.Info("order placed", "order_id", order.ID, "user_id", userID, "item_count", len(items), "total_amount", order.TotalAmount)
61		observability.M.OrdersCreated.Add(1)
62	
63		return order, nil
64	}
65	
66	// ---------------------------------------------------------------
67	// Student actions
68	// ---------------------------------------------------------------
69	
70	// ConfirmPayment transitions an order from pending_payment → pending_shipment.
71	// Only the order owner may confirm payment.
72	func (s *OrderService) ConfirmPayment(orderID, userID int64) error {
73		order, err := s.orderRepo.GetByID(orderID)
74		if err != nil {
75			return fmt.Errorf("service: ConfirmPayment: %w", err)
76		}
77		if order.UserID != userID {
78			return errors.New("service: ConfirmPayment: not authorized")
79		}
80		if order.Status != "pending_payment" {
81			return fmt.Errorf("service: ConfirmPayment: order is %q, expected pending_payment", order.Status)
82		}
83		if err := s.orderRepo.Transition(orderID, userID, "pending_shipment", "payment confirmed", s.materialRepo); err != nil {
84			return err
85		}
86		observability.Orders.Info("payment confirmed", "order_id", orderID, "user_id", userID)
87		return nil
88	}
89	
90	// CancelOrder cancels an order. Business rules:
91	//   - Students can only cancel their own orders when in pending_payment.
92	//   - Clerks cannot cancel orders.
93	//   - Admins/instructors can cancel pending_payment or pending_shipment orders.
94	//   - Only admins can cancel in_transit orders.
95	func (s *OrderService) CancelOrder(orderID, actorID int64, role string) error {
96		order, err := s.orderRepo.GetByID(orderID)
97		if err != nil {
98			return fmt.Errorf("service: CancelOrder: %w", err)
99		}
100	
101		switch role {
102		case "student":
103			if order.UserID != actorID {
104				return errors.New("service: CancelOrder: not authorized")
105			}
106			if order.Status != "pending_payment" {
107				return fmt.Errorf("service: CancelOrder: students may only cancel orders in pending_payment (current: %q)", order.Status)
108			}
109		case "admin", "instructor":
110			if order.Status == "in_transit" && role != "admin" {
111				return errors.New("service: CancelOrder: only admins can cancel in-transit orders")
112			}
113			if order.Status == "completed" {
114				return errors.New("service: CancelOrder: completed orders cannot be canceled")
115			}
116			if order.Status == "canceled" {
117				return errors.New("service: CancelOrder: order is already canceled")
118			}
119		case "clerk":
120			return errors.New("service: CancelOrder: clerks are not permitted to cancel orders")
121		default:
122			return errors.New("service: CancelOrder: unknown role")
123		}
124	
125		note := fmt.Sprintf("canceled by %s (id=%d)", role, actorID)
126		if err := s.orderRepo.Transition(orderID, actorID, "canceled", note, s.materialRepo); err != nil {
127			return err
128		}
129		observability.Orders.Info("order canceled", "order_id", orderID, "actor_id", actorID, "role", role, "reason", "user_requested")
130		observability.M.OrdersCanceled.Add(1)
131		return nil
132	}
