135	// Clerk actions
136	// ---------------------------------------------------------------
137	
138	// MarkShipped transitions an order from pending_shipment → in_transit.
139	// Only clerks (or admins) may call this.
140	func (s *OrderService) MarkShipped(orderID, actorID int64) error {
141		order, err := s.orderRepo.GetByID(orderID)
142		if err != nil {
143			return fmt.Errorf("service: MarkShipped: %w", err)
144		}
145		if order.Status != "pending_shipment" {
146			return fmt.Errorf("service: MarkShipped: order is %q, expected pending_shipment", order.Status)
147		}
148		return s.orderRepo.Transition(orderID, actorID, "in_transit", "order shipped", s.materialRepo)
149	}
