262	// ---------------------------------------------------------------
263	// State machine transition
264	// ---------------------------------------------------------------
265	
266	// validTransitions maps (fromStatus, toStatus) pairs that are permitted.
267	var validTransitions = map[string]map[string]bool{
268		"pending_payment": {
269			"pending_shipment": true,
270			"canceled":         true,
271		},
272		"pending_shipment": {
273			"in_transit": true,
274			"canceled":   true,
275		},
276		"in_transit": {
277			"completed": true,
278			"canceled":  true,
279		},
280	}
281	
282	// Transition validates and applies an order status transition within a
283	// transaction. It also:
284	//   - Updates auto_close_at: pending_shipment → now+72h, all others → NULL.
285	//   - On cancel: rolls back inventory (available_qty += qty, reserved_qty -= qty).
286	//   - On completed: decrements reserved_qty (items are physically fulfilled).
287	//   - Inserts an order_event row.
288	func (r *OrderRepository) Transition(orderID, actorID int64, toStatus, note string, materialRepo *MaterialRepository) error {
289		tx, err := r.db.Begin()
290		if err != nil {
291			return fmt.Errorf("repository: Transition: begin tx: %w", err)
292		}
293		defer tx.Rollback() //nolint:errcheck
294	
295		// Load current status.
296		var fromStatus string
297		if err := tx.QueryRow(`SELECT status FROM orders WHERE id = ?`, orderID).Scan(&fromStatus); err != nil {
298			if errors.Is(err, sql.ErrNoRows) {
299				return fmt.Errorf("repository: Transition: order %d not found", orderID)
300			}
301			return fmt.Errorf("repository: Transition: load status: %w", err)
302		}
303	
304		// Validate transition.
305		allowed, ok := validTransitions[fromStatus]
306		if !ok || !allowed[toStatus] {
307			return fmt.Errorf("repository: Transition: invalid transition %q → %q", fromStatus, toStatus)
308		}
309	
310		// Determine new auto_close_at value.
311		var autoCloseExpr string
312		switch toStatus {
313		case "pending_shipment":
314			autoCloseExpr = "datetime('now', '+72 hours')"
315		default:
316			autoCloseExpr = "NULL"
317		}
318	
319		// Stamp completed_at exactly once — when the order first reaches "completed".
320		// This timestamp is the authoritative anchor for the 14-day return window.
321		var completedAtExpr string
322		if toStatus == "completed" {
323			completedAtExpr = ", completed_at = datetime('now')"
324		}
325	
326		updateOrderQ := fmt.Sprintf(`
327			UPDATE orders
328			SET    status        = ?,
329			       auto_close_at = %s,
330			       updated_at    = datetime('now')%s
331			WHERE  id = ?`, autoCloseExpr, completedAtExpr)
332	
333		if _, err := tx.Exec(updateOrderQ, toStatus, orderID); err != nil {
334			return fmt.Errorf("repository: Transition: update order: %w", err)
335		}
336	
337		// Handle inventory side effects.
338		if toStatus == "canceled" {
339			// Roll back reserved inventory for every item.
340			const itemsQ = `SELECT material_id, qty FROM order_items WHERE order_id = ?`
341			rows, err := tx.Query(itemsQ, orderID)
342			if err != nil {
343				return fmt.Errorf("repository: Transition: query items for rollback: %w", err)
344			}
345			type itemRef struct {
346				materialID int64
347				qty        int
348			}
349			var items []itemRef
350			for rows.Next() {
351				var it itemRef
352				if err := rows.Scan(&it.materialID, &it.qty); err != nil {
353					rows.Close()
354					return err
355				}
356				items = append(items, it)
357			}
358			rows.Close()
359			if err := rows.Err(); err != nil {
360				return err
361			}
362	
363			const rollbackQ = `
364				UPDATE materials
365				SET    available_qty = available_qty + ?,
366				       reserved_qty  = CASE WHEN reserved_qty - ? < 0 THEN 0 ELSE reserved_qty - ? END,
367				       updated_at    = datetime('now')
368				WHERE  id = ?`
369			for _, it := range items {
370				if _, err := tx.Exec(rollbackQ, it.qty, it.qty, it.qty, it.materialID); err != nil {
371					return fmt.Errorf("repository: Transition: rollback inventory material %d: %w", it.materialID, err)
372				}
373			}
374		} else if toStatus == "completed" {
375			// Decrement reserved_qty — items are physically handed over.
376			const itemsQ = `SELECT material_id, qty FROM order_items WHERE order_id = ?`
377			rows, err := tx.Query(itemsQ, orderID)
378			if err != nil {
379				return fmt.Errorf("repository: Transition: query items for fulfillment: %w", err)
380			}
381			type itemRef struct {
382				materialID int64
383				qty        int
384			}
385			var items []itemRef
386			for rows.Next() {
387				var it itemRef
388				if err := rows.Scan(&it.materialID, &it.qty); err != nil {
389					rows.Close()
390					return err
391				}
392				items = append(items, it)
393			}
394			rows.Close()
395			if err := rows.Err(); err != nil {
396				return err
397			}
398	
399			const fulfillQ = `
400				UPDATE materials
401				SET    reserved_qty = CASE WHEN reserved_qty - ? < 0 THEN 0 ELSE reserved_qty - ? END,
402				       updated_at   = datetime('now')
403				WHERE  id = ?`
404			for _, it := range items {
405				if _, err := tx.Exec(fulfillQ, it.qty, it.qty, it.materialID); err != nil {
406					return fmt.Errorf("repository: Transition: fulfill inventory material %d: %w", it.materialID, err)
407				}
408			}
409	
410			// Mark order_items as fulfilled.
411			if _, err := tx.Exec(`UPDATE order_items SET fulfillment_status = 'fulfilled' WHERE order_id = ?`, orderID); err != nil {
412				return fmt.Errorf("repository: Transition: mark items fulfilled: %w", err)
413			}
414		}
415	
416		// Insert order_event.
417		var notePtr *string
418		if note != "" {
419			notePtr = &note
420		}
421		const eventQ = `
422			INSERT INTO order_events (order_id, from_status, to_status, actor_id, note)
423			VALUES (?, ?, ?, ?, ?)`
424		if _, err := tx.Exec(eventQ, orderID, fromStatus, toStatus, actorID, notePtr); err != nil {
425			return fmt.Errorf("repository: Transition: insert order_event: %w", err)
426		}
427	
428		return tx.Commit()
429	}
