433	// ---------------------------------------------------------------
434	
435	// CreateBackorder creates a backorder record for an order item.
436	func (r *OrderRepository) CreateBackorder(orderItemID int64, qty int) (*models.Backorder, error) {
437		const q = `
438			INSERT INTO backorders (order_item_id, qty)
