668	// Auto-close (scheduler entry point)
669	// ---------------------------------------------------------------
670	
671	// CloseOverdueOrders cancels all orders whose auto_close_at has passed and
672	// whose status is pending_payment or pending_shipment. Returns the count of
673	// orders closed.
674	func (r *OrderRepository) CloseOverdueOrders(materialRepo *MaterialRepository) (int, error) {
675		const selectQ = `
676			SELECT id, status
677			FROM   orders
678			WHERE  status IN ('pending_payment', 'pending_shipment')
679			  AND  auto_close_at IS NOT NULL
680			  AND  auto_close_at < datetime('now')`
681	
682		rows, err := r.db.Query(selectQ)
683		if err != nil {
684			return 0, fmt.Errorf("repository: CloseOverdueOrders: query: %w", err)
685		}
686		type row struct {
687			id     int64
688			status string
689		}
690		var overdue []row
691		for rows.Next() {
692			var rw row
693			if err := rows.Scan(&rw.id, &rw.status); err != nil {
694				rows.Close()
695				return 0, err
696			}
697			overdue = append(overdue, rw)
698		}
699		rows.Close()
700		if err := rows.Err(); err != nil {
701			return 0, err
702		}
703	
704		closed := 0
705		for _, rw := range overdue {
706			note := "auto-closed: payment timeout"
707			if rw.status == "pending_shipment" {
708				note = "auto-closed: shipment timeout"
709			}
710			if err := r.Transition(rw.id, 0, "canceled", note, materialRepo); err != nil {
711				// Log but continue — don't abort the whole batch on a single failure.
712				continue
713			}
714			closed++
715		}
716	
717		return closed, nil
718	}
