421	// ---------------------------------------------------------------
422	// helpers
423	// ---------------------------------------------------------------
424	
425	// recordReturnInternal records the return event and releases inventory without
426	// validating a return_request. It is used internally by RecordExchange, which
427	// has already validated the exchange request before splitting into legs.
428	func (s *DistributionService) recordReturnInternal(orderID, materialID, actorID int64, scanID string, qty int) error {
429		orderIDPtr := &orderID
430		actorIDPtr := &actorID
431		scanIDPtr := &scanID
432	
433		evt := &models.DistributionEvent{
434			OrderID:     orderIDPtr,
435			MaterialID:  materialID,
436			Qty:         qty,
437			EventType:   "returned",
438			ScanID:      scanIDPtr,
439			ActorID:     actorIDPtr,
440			CustodyFrom: stringPtr("student"),
441			CustodyTo:   stringPtr("clerk"),
442		}
443		if _, err := s.distRepo.RecordEvent(evt); err != nil {
444			return fmt.Errorf("record event: %w", err)
445		}
446		// Return copies to available stock (post-fulfillment: only available_qty).
447		if err := s.materialRepo.ReturnToStock(materialID, qty); err != nil {
448			return fmt.Errorf("return to stock: %w", err)
449		}
450		return nil
451	}
