67		// Enforce explicit allowlist: the order owner may always view their own
68		// order; admin, instructor, and clerk have operational need-to-know.
69		// All other roles (e.g. moderator) are denied.
70		switch user.Role {
71		case "admin", "instructor", "clerk":
72			// Permitted — these roles have operational need-to-know for order details.
73		case "student":
