75				observability.Security.Warn("unauthorized order access attempt",
76					"user_id", user.ID, "order_id", id, "order_owner_id", order.UserID, "ip", c.IP())
77				return apiErr(c, fiber.StatusForbidden, "You do not have permission to perform this action")
78			}
