80			observability.Security.Warn("unauthorized order access attempt by non-student role",
81				"user_id", user.ID, "role", user.Role, "order_id", id, "ip", c.IP())
82			return apiErr(c, fiber.StatusForbidden, "You do not have permission to perform this action")
83		}
