151	// MarkDelivered transitions an order from in_transit → completed.
152	// Only clerks (or admins) may call this.
153	func (s *OrderService) MarkDelivered(orderID, actorID int64) error {
154		order, err := s.orderRepo.GetByID(orderID)
155		if err != nil {
156			return fmt.Errorf("service: MarkDelivered: %w", err)
157		}
158		if order.Status != "in_transit" {
159			return fmt.Errorf("service: MarkDelivered: order is %q, expected in_transit", order.Status)
160		}
161		return s.orderRepo.Transition(orderID, actorID, "completed", "order delivered", s.materialRepo)
162	}
163	
164	// ---------------------------------------------------------------
165	// Returns / Exchanges / Refunds
166	// ---------------------------------------------------------------
167	
168	// RequestReturn submits a return/exchange/refund request for an order.
169	// Rules:
170	//   - The order must belong to the requesting user.
171	//   - Return/exchange: allowed only within 14 days of order completion.
172	//   - Refund: also allowed only within 14 days; requires manager role enforcement
173	//     at the handler layer (admin or instructor).
174	//   - Only one pending request may be open per order at a time.
175	//   - For exchange requests, replacementMaterialID identifies the desired
176	//     replacement item; it is stored and validated at approval time.
177	func (s *OrderService) RequestReturn(orderID, userID int64, reqType, reason string, replacementMaterialID *int64) (*models.ReturnRequest, error) {
178		order, err := s.orderRepo.GetByID(orderID)
179		if err != nil {
180			return nil, fmt.Errorf("service: RequestReturn: %w", err)
181		}
182		if order.UserID != userID {
183			return nil, errors.New("service: RequestReturn: not authorized")
184		}
185		if order.Status != "completed" {
186			return nil, errors.New("service: RequestReturn: returns are only allowed on completed orders")
187		}
188	
189		switch reqType {
190		case "return", "exchange", "refund":
191			// valid types
192		default:
193			return nil, fmt.Errorf("service: RequestReturn: invalid type %q (must be return, exchange, or refund)", reqType)
194		}
195	
196		// Enforce 14-day window anchored to the completion timestamp, not updated_at.
197		// updated_at changes on every status mutation; completed_at is stamped exactly
198		// once when the order transitions to "completed" and never changes afterward.
199		if order.CompletedAt == nil {
200			return nil, errors.New("service: RequestReturn: order has no completion timestamp")
201		}
202		if !repository.WithinReturnWindow(*order.CompletedAt) {
203			return nil, errors.New("service: RequestReturn: the 14-day return window has expired")
204		}
205	
206		// Check for an already-pending request on this order.
207		existing, err := s.orderRepo.GetReturnRequestsByUser(userID)
208		if err != nil {
209			return nil, fmt.Errorf("service: RequestReturn: check existing: %w", err)
210		}
211		for _, rr := range existing {
212			if rr.OrderID == orderID && rr.Status == "pending" {
213				return nil, errors.New("service: RequestReturn: a pending return request already exists for this order")
214			}
215		}
216	
217		rr, err := s.orderRepo.CreateReturnRequest(orderID, userID, reqType, reason, replacementMaterialID)
218		if err != nil {
219			return nil, fmt.Errorf("service: RequestReturn: %w", err)
220		}
221		observability.Orders.Info("return requested", "order_id", orderID, "type", reqType)
222		return rr, nil
223	}
224	
225	// ApproveReturn approves a return request.
226	// Only admins and instructors (managers) may approve.
227	// For exchange requests, the replacement_material_id must be set on the request
228	// and the replacement material must have sufficient available stock.
229	// When the request type is "refund" or "return", a financial_transaction record
230	// is created for traceability.
231	func (s *OrderService) ApproveReturn(requestID, actorID int64, role string) error {
232		if role != "admin" && role != "instructor" {
233			return errors.New("service: ApproveReturn: only managers (admin/instructor) may approve return requests")
234		}
235		rr, err := s.orderRepo.GetReturnRequestByID(requestID)
236		if err != nil {
237			return fmt.Errorf("service: ApproveReturn: %w", err)
238		}
239		if rr.Status != "pending" {
240			return fmt.Errorf("service: ApproveReturn: request is already %q", rr.Status)
241		}
242	
243		// For exchange requests, verify replacement inventory before approving.
244		if rr.Type == "exchange" {
245			if rr.ReplacementMaterialID == nil {
246				return errors.New("service: ApproveReturn: exchange request has no replacement material specified")
247			}
248			replacement, err := s.materialRepo.GetByID(*rr.ReplacementMaterialID)
249			if err != nil {
250				return fmt.Errorf("service: ApproveReturn: load replacement material: %w", err)
251			}
252			if replacement.AvailableQty < 1 {
253				return fmt.Errorf("service: ApproveReturn: replacement material %q has no available stock", replacement.Title)
254			}
255		}
256	
257		// For refund/return types, approval and financial record must both succeed
258		// atomically so the audit trail is never broken.
259		if rr.Type == "refund" || rr.Type == "return" {
260			amount := 0.0
261			if order, oErr := s.orderRepo.GetByID(rr.OrderID); oErr == nil {
262				amount = order.TotalAmount
263			}
264			note := "approved " + rr.Type + " request"
265			if err := s.orderRepo.ApproveReturnWithFinancialRecord(
266				requestID, rr.OrderID, actorID, "refund", amount, note,
267			); err != nil {
268				return fmt.Errorf("service: ApproveReturn: atomic approval+financial record: %w", err)
269			}
270		} else {
271			if err := s.orderRepo.ResolveReturn(requestID, actorID, true); err != nil {
272				return err
273			}
274		}
275	
276		observability.Orders.Info("return approved", "request_id", requestID, "actor_id", actorID, "role", role, "type", rr.Type)
277		return nil
278	}
279	
280	// RejectReturn rejects a return request.
281	// Clerks, admins, and instructors may reject.
282	func (s *OrderService) RejectReturn(requestID, actorID int64) error {
283		rr, err := s.orderRepo.GetReturnRequestByID(requestID)
284		if err != nil {
285			return fmt.Errorf("service: RejectReturn: %w", err)
286		}
287		if rr.Status != "pending" {
288			return fmt.Errorf("service: RejectReturn: request is already %q", rr.Status)
289		}
290		if err := s.orderRepo.ResolveReturn(requestID, actorID, false); err != nil {
291			return err
292		}
293		observability.Orders.Info("return rejected", "request_id", requestID, "actor_id", actorID)
294		return nil
295	}
