612	// ApproveReturnWithFinancialRecord atomically approves a return request and
613	// creates the corresponding financial_transactions row in the same database
614	// transaction. If the financial record cannot be written the approval is rolled
615	// back and the error is returned, maintaining strict audit linkage.
616	func (r *OrderRepository) ApproveReturnWithFinancialRecord(
617		requestID, orderID, actorID int64,
618		txType string,
619		amount float64,
620		note string,
621	) error {
622		tx, err := r.db.Begin()
623		if err != nil {
624			return fmt.Errorf("repository: ApproveReturnWithFinancialRecord: begin: %w", err)
625		}
626		defer func() {
627			if err != nil {
628				_ = tx.Rollback()
629			}
630		}()
631	
632		const resolveQ = `
633			UPDATE return_requests
634			SET    status      = 'approved',
635			       resolved_at = datetime('now'),
636			       resolved_by = ?
637			WHERE  id = ? AND status = 'pending'`
638	
639		res, err := tx.Exec(resolveQ, actorID, requestID)
640		if err != nil {
641			return fmt.Errorf("repository: ApproveReturnWithFinancialRecord: resolve: %w", err)
642		}
643		n, err := res.RowsAffected()
644		if err != nil {
645			return fmt.Errorf("repository: ApproveReturnWithFinancialRecord: rows affected: %w", err)
646		}
647		if n == 0 {
648			return fmt.Errorf("repository: ApproveReturnWithFinancialRecord: request %d not found or already resolved", requestID)
649		}
650	
651		var notePtr *string
652		if note != "" {
653			notePtr = &note
654		}
655		const ftQ = `
656			INSERT INTO financial_transactions
657			            (order_id, return_request_id, type, amount, status, note, actor_id)
658			VALUES      (?, ?, ?, ?, 'pending', ?, ?)`
659	
660		if _, err = tx.Exec(ftQ, orderID, requestID, txType, amount, notePtr, actorID); err != nil {
661			return fmt.Errorf("repository: ApproveReturnWithFinancialRecord: financial record: %w", err)
662		}
663	
664		return tx.Commit()
665	}
