899	// returnWindowDays is the maximum number of days after order completion
900	// within which a return request may be filed.
901	const returnWindowDays = 14
902	
903	// WithinReturnWindow reports whether the given completedAt timestamp is
904	// within the 14-day return window. completedAt must be in RFC3339 format.
905	func WithinReturnWindow(completedAt string) bool {
906		t, err := time.Parse(time.RFC3339, completedAt)
907		if err != nil {
908			// Fallback: attempt SQLite datetime format.
909			t, err = time.Parse("2006-01-02 15:04:05", completedAt)
910			if err != nil {
911				return false
912			}
913		}
914		return time.Since(t) <= time.Duration(returnWindowDays)*24*time.Hour
915	}
