content.text:
1	package services
2	
3	import (
4		"database/sql"
5		"errors"
6		"fmt"
7	
8		"w2t86/internal/models"
9		"w2t86/internal/observability"
10		"w2t86/internal/repository"
11	)
12	
13	// IssueItem identifies a single material line to be physically issued.
14	// IssuedQty is the number of copies the clerk is handing out right now; it may
15	// be less than the full ordered quantity, in which case a backorder is created
16	// for the remainder.  When IssuedQty is 0 it defaults to the full ordered qty.
17	type IssueItem struct {
18		MaterialID int64
19		Qty        int // total ordered quantity
20		IssuedQty  int // quantity being issued in this operation (0 = full qty)
21	}
22	
23	// DistributionService orchestrates all clerk-facing distribution operations:
24	// issuing, returning, exchanging, and reissuing physical copies.
25	type DistributionService struct {
26		distRepo     *repository.DistributionRepository
27		orderRepo    *repository.OrderRepository
28		materialRepo *repository.MaterialRepository
29	}
30	
31	// NewDistributionService wires the service to its three repositories.
32	func NewDistributionService(
33		dr *repository.DistributionRepository,
34		or *repository.OrderRepository,
35		mr *repository.MaterialRepository,
36	) *DistributionService {
37		return &DistributionService{
38			distRepo:     dr,
39			orderRepo:    or,
40			materialRepo: mr,
41		}
42	}
43	
44	// ---------------------------------------------------------------
45	// Issue
46	// ---------------------------------------------------------------
47	
48	// IssueItems records an "issued" distribution event for every item in the
49	// slice, marks the corresponding order_items as fulfilled, and — when all
50	// items for the order are fulfilled — advances the order status to in_transit.
51	//
52	// scanID is a barcode / copy identifier that binds the physical copy to the
53	// event.  It is shared across all items in a single issue batch.
54	func (s *DistributionService) IssueItems(orderID, actorID int64, scanID string, items []IssueItem) error {
55		if len(items) == 0 {
56			return errors.New("service: IssueItems: at least one item required")
57		}
58	
59		order, err := s.orderRepo.GetByID(orderID)
60		if err != nil {
61			if errors.Is(err, sql.ErrNoRows) {
62				return fmt.Errorf("service: IssueItems: order %d not found", orderID)
63			}
64			return fmt.Errorf("service: IssueItems: load order: %w", err)
65		}
66		if order.Status != "pending_shipment" && order.Status != "in_transit" {
67			return fmt.Errorf("service: IssueItems: order %d is not ready to issue (status=%s)", orderID, order.Status)
68		}
69	
70		scanIDPtr := &scanID
71		actorIDPtr := &actorID
72		orderIDPtr := &orderID
73	
74		// Load the authoritative order line items and build a lookup map.
75		orderItems, err := s.orderRepo.GetItemsByOrderID(orderID)
76		if err != nil {
77			return fmt.Errorf("service: IssueItems: load order items: %w", err)
78		}
79		orderedQty := make(map[int64]int, len(orderItems))
80		for _, oi := range orderItems {
81			orderedQty[oi.MaterialID] = oi.Qty
82		}
83	
84		for _, item := range items {
85			// Reject materials that are not part of this order.
86			oqty, ok := orderedQty[item.MaterialID]
87			if !ok {
88				return fmt.Errorf("service: IssueItems: material %d is not part of order %d", item.MaterialID, orderID)
89			}
90	
91			issued := item.IssuedQty
92			if issued <= 0 {
93				// Default to the full DB-authoritative ordered quantity — never the
94				// client-supplied item.Qty, which could be forged lower to fake
95				// full fulfillment with fewer physical copies.
96				issued = oqty
97			}
98			if issued <= 0 {
99				return fmt.Errorf("service: IssueItems: qty must be positive for material %d", item.MaterialID)
100			}
101			// Issued quantity must not exceed the DB-authoritative ordered quantity.
102			if issued > oqty {
103				return fmt.Errorf("service: IssueItems: issued qty (%d) exceeds ordered qty (%d) for material %d",
104					issued, oqty, item.MaterialID)
105			}
106	
107			evt := &models.DistributionEvent{
108				OrderID:     orderIDPtr,
109				MaterialID:  item.MaterialID,
110				Qty:         issued, // record only the quantity actually handed out
111				EventType:   "issued",
112				ScanID:      scanIDPtr,
113				ActorID:     actorIDPtr,
114				CustodyFrom: stringPtr("clerk"),
115				CustodyTo:   stringPtr("student"),
116			}
117			if _, err := s.distRepo.RecordEvent(evt); err != nil {
118				return fmt.Errorf("service: IssueItems: record event for material %d: %w", item.MaterialID, err)
119			}
120		}
121	
122		// Mark order items as fulfilled and potentially advance order status.
123		if err := s.markItemsFulfilled(orderID, actorID, items); err != nil {
124			return fmt.Errorf("service: IssueItems: mark fulfilled: %w", err)
125		}
126	
127		for _, item := range items {
128			observability.Distribution.Info("item issued", "order_id", orderID, "material_id", item.MaterialID, "qty", item.Qty, "scan_id", scanID, "actor_id", actorID)
129		}
130		return nil
131	}
132	
133	// markItemsFulfilled updates fulfillment_status for each issued item.
134	// When the issued quantity equals the ordered quantity the item is marked
135	// "fulfilled"; when it is less, the item is marked "backordered" and a
136	// backorder record is created for the shortfall.
137	// The order is advanced from pending_shipment → in_transit on the first issue.
138	func (s *DistributionService) markItemsFulfilled(orderID, actorID int64, items []IssueItem) error {
139		for _, item := range items {
140			issued := item.IssuedQty
141			if issued <= 0 {
142				issued = item.Qty
143			}
144	
145			if issued >= item.Qty {
146				// Fully satisfied — mark fulfilled.
147				if err := s.orderRepo.MarkOrderItemFulfilled(orderID, item.MaterialID); err != nil {
148					return fmt.Errorf("markItemsFulfilled: mark fulfilled material %d: %w", item.MaterialID, err)
149				}
150			} else {
151				// Partial issue — mark backordered and record the shortfall.
152				if err := s.orderRepo.MarkOrderItemBackordered(orderID, item.MaterialID); err != nil {
153					return fmt.Errorf("markItemsFulfilled: mark backordered material %d: %w", item.MaterialID, err)
154				}
155				itemID, err := s.orderRepo.GetOrderItemID(orderID, item.MaterialID)
156				if err != nil {
157					return fmt.Errorf("markItemsFulfilled: get order_item_id material %d: %w", item.MaterialID, err)
158				}
159				shortfall := item.Qty - issued
160				if _, err := s.orderRepo.CreateBackorder(itemID, shortfall); err != nil {
161					return fmt.Errorf("markItemsFulfilled: create backorder material %d: %w", item.MaterialID, err)
162				}
163				observability.Distribution.Warn("partial issue — backorder created",
164					"order_id", orderID, "material_id", item.MaterialID,
165					"issued", issued, "shortfall", shortfall)
166			}
167		}
168	
169		// Advance order from pending_shipment → in_transit on first issue.
170		order, err := s.orderRepo.GetByID(orderID)
171		if err != nil {
172			return err
173		}
174		if order.Status == "pending_shipment" {
175			if err := s.orderRepo.Transition(orderID, actorID, "in_transit", "items issued by clerk", s.materialRepo); err != nil {
176				return fmt.Errorf("markItemsFulfilled: advance to in_transit: %w", err)
177			}
178		}
179	
180		return nil
181	}
182	
183	// ---------------------------------------------------------------
184	// Return
185	// ---------------------------------------------------------------
186	
187	// RecordReturn records a "returned" distribution event and releases inventory
188	// (increments available_qty by qty).
189	//
190	// returnRequestID must reference an approved return_request of type "return"
191	// for orderID. The call is rejected if the request does not exist, is not yet
192	// approved, or belongs to a different order.
193	func (s *DistributionService) RecordReturn(orderID, materialID, actorID, returnRequestID int64, scanID string, qty int) error {
194		if qty <= 0 {
195			return errors.New("service: RecordReturn: qty must be positive")
196		}
197	
198		// Require an approved return request of the correct type.
199		rr, err := s.orderRepo.GetReturnRequestByID(returnRequestID)
200		if err != nil {
201			return fmt.Errorf("service: RecordReturn: load return request: %w", err)
202		}
203		if rr.Status != "approved" {
204			return fmt.Errorf("service: RecordReturn: return request %d is not approved (status=%s)", returnRequestID, rr.Status)
205		}
206		if rr.OrderID != orderID {
207			return fmt.Errorf("service: RecordReturn: return request %d belongs to order %d, not %d", returnRequestID, rr.OrderID, orderID)
208		}
209		if rr.Type != "return" {
210			return fmt.Errorf("service: RecordReturn: return request %d has wrong type %q (expected 'return')", returnRequestID, rr.Type)
211		}
212	
213		// Verify order exists.
214		if _, err := s.orderRepo.GetByID(orderID); err != nil {
215			if errors.Is(err, sql.ErrNoRows) {
216				return fmt.Errorf("service: RecordReturn: order %d not found", orderID)
217			}
218			return fmt.Errorf("service: RecordReturn: load order: %w", err)
219		}
220	
221		orderIDPtr := &orderID
222		actorIDPtr := &actorID
223		scanIDPtr := &scanID
224	
225		evt := &models.DistributionEvent{
226			OrderID:     orderIDPtr,
227			MaterialID:  materialID,
228			Qty:         qty,
229			EventType:   "returned",
230			ScanID:      scanIDPtr,
231			ActorID:     actorIDPtr,
232			CustodyFrom: stringPtr("student"),
233			CustodyTo:   stringPtr("clerk"),
234		}
235		if _, err := s.distRepo.RecordEvent(evt); err != nil {
236			return fmt.Errorf("service: RecordReturn: record event: %w", err)
237		}
238	
239		// Return copies to available stock. The order is already completed so
240		// reserved_qty for these items has already been decremented by the
241		// completion transition; we only need to increment available_qty.
242		if err := s.materialRepo.ReturnToStock(materialID, qty); err != nil {
243			return fmt.Errorf("service: RecordReturn: return to stock: %w", err)
244		}
245	
246		observability.Distribution.Info("item returned", "order_id", orderID, "material_id", materialID, "qty", qty, "scan_id", scanID, "actor_id", actorID)
247		return nil
248	}
249	
250	// ---------------------------------------------------------------
251	// Exchange
252	// ---------------------------------------------------------------
253	
254	// RecordExchange swaps an old copy for a new one in a single logical operation:
255	//  1. Validates the approved exchange request.
256	//  2. Records a "returned" event for oldMaterialID.
257	//  3. Verifies the new material has available stock.
258	//  4. Records an "issued" event for newMaterialID and decrements its
259	//     available_qty.
260	//
261	// returnRequestID must reference an approved return_request of type "exchange"
262	// for orderID.
263	func (s *DistributionService) RecordExchange(orderID, oldMaterialID, newMaterialID, actorID, returnRequestID int64, scanID string, qty int) error {
264		if qty <= 0 {
265			return errors.New("service: RecordExchange: qty must be positive")
266		}
267	
268		// Require an approved exchange request of the correct type.
269		rr, err := s.orderRepo.GetReturnRequestByID(returnRequestID)
270		if err != nil {
271			return fmt.Errorf("service: RecordExchange: load return request: %w", err)
272		}
273		if rr.Status != "approved" {
274			return fmt.Errorf("service: RecordExchange: return request %d is not approved (status=%s)", returnRequestID, rr.Status)
275		}
276		if rr.OrderID != orderID {
277			return fmt.Errorf("service: RecordExchange: return request %d belongs to order %d, not %d", returnRequestID, rr.OrderID, orderID)
278		}
279		if rr.Type != "exchange" {
280			return fmt.Errorf("service: RecordExchange: return request %d has wrong type %q (expected 'exchange')", returnRequestID, rr.Type)
281		}
282	
283		// Return the old copy (releases its inventory).
284		// We pass 0 as returnRequestID to the inner RecordReturn because the
285		// exchange request already covers both legs; RecordReturn's own request
286		// check is bypassed here via the internal call path.
287		if err := s.recordReturnInternal(orderID, oldMaterialID, actorID, scanID, qty); err != nil {
288			return fmt.Errorf("service: RecordExchange: return old: %w", err)
289		}
290	
291		// Check new material stock.
292		newMat, err := s.materialRepo.GetByID(newMaterialID)
293		if err != nil {
294			if errors.Is(err, sql.ErrNoRows) {
295				return fmt.Errorf("service: RecordExchange: new material %d not found", newMaterialID)
296			}
297			return fmt.Errorf("service: RecordExchange: load new material: %w", err)
298		}
299		if newMat.AvailableQty < qty {
300			return fmt.Errorf("service: RecordExchange: insufficient stock for material %q (available %d, requested %d)",
301				newMat.Title, newMat.AvailableQty, qty)
302		}
303	
304		orderIDPtr := &orderID
305		actorIDPtr := &actorID
306		newScanID := scanID + "_exch"
307		scanIDPtr := &newScanID
308	
309		evt := &models.DistributionEvent{
310			OrderID:     orderIDPtr,
311			MaterialID:  newMaterialID,
312			Qty:         qty,
313			EventType:   "issued",
314			ScanID:      scanIDPtr,
315			ActorID:     actorIDPtr,
316			CustodyFrom: stringPtr("clerk"),
317			CustodyTo:   stringPtr("student"),
318		}
319		if _, err := s.distRepo.RecordEvent(evt); err != nil {
320			return fmt.Errorf("service: RecordExchange: record issue event: %w", err)
321		}
322	
323		// Directly decrement available_qty for the newly issued material. Because
324		// the exchange is performed post-fulfillment the new copy goes straight
325		// to the student without a reservation phase, so DirectIssue (available
326		// only) is correct — Reserve would incorrectly increment reserved_qty.
327		if err := s.materialRepo.DirectIssue(newMaterialID, qty); err != nil {
328			return fmt.Errorf("service: RecordExchange: direct issue new material: %w", err)
329		}
330	
331		observability.Distribution.Info("item exchanged", "order_id", orderID, "old_material_id", oldMaterialID, "new_material_id", newMaterialID, "qty", qty, "actor_id", actorID)
332		return nil
333	}
334	
335	
336	// ---------------------------------------------------------------
337	// Reissue
338	// ---------------------------------------------------------------
339	
340	// ReissueItem handles lost or damaged copy replacement:
341	//   - Records a "lost" or "damaged" event for oldScanID (marking it out of
342	//     circulation).
343	//   - Records a new "issued" event for newScanID.
344	//
345	// reason must be "lost" or "damaged".
346	func (s *DistributionService) ReissueItem(orderID, materialID, actorID int64, oldScanID, newScanID, reason string) error {
347		if reason != "lost" && reason != "damaged" {
348			return fmt.Errorf("service: ReissueItem: invalid reason %q (must be 'lost' or 'damaged')", reason)
349		}
350		if oldScanID == "" || newScanID == "" {
351			return errors.New("service: ReissueItem: both oldScanID and newScanID are required")
352		}
353	
354		// Verify order exists.
355		if _, err := s.orderRepo.GetByID(orderID); err != nil {
356			if errors.Is(err, sql.ErrNoRows) {
357				return fmt.Errorf("service: ReissueItem: order %d not found", orderID)
358			}
359			return fmt.Errorf("service: ReissueItem: load order: %w", err)
360		}
361	
362		orderIDPtr := &orderID
363		actorIDPtr := &actorID
364	
365		// Record the loss/damage event for the old scan ID.
366		oldEvt := &models.DistributionEvent{
367			OrderID:    orderIDPtr,
368			MaterialID: materialID,
369			Qty:        1,
370			EventType:  reason, // "lost" or "damaged"
371			ScanID:     &oldScanID,
372			ActorID:    actorIDPtr,
373		}
374		if _, err := s.distRepo.RecordEvent(oldEvt); err != nil {
375			return fmt.Errorf("service: ReissueItem: record %s event: %w", reason, err)
376		}
377	
378		// Issue the replacement copy.
379		newEvt := &models.DistributionEvent{
380			OrderID:     orderIDPtr,
381			MaterialID:  materialID,
382			Qty:         1,
383			EventType:   "issued",
384			ScanID:      &newScanID,
385			ActorID:     actorIDPtr,
386			CustodyFrom: stringPtr("clerk"),
387			CustodyTo:   stringPtr("student"),
388		}
389		if _, err := s.distRepo.RecordEvent(newEvt); err != nil {
390			return fmt.Errorf("service: ReissueItem: record replacement issue event: %w", err)
391		}
392	
393		observability.Distribution.Info("item reissued", "old_scan_id", oldScanID, "new_scan_id", newScanID, "reason", reason)
394		return nil
395	}
396	
397	// ---------------------------------------------------------------
398	// Ledger / chain queries — thin pass-through
399	// ---------------------------------------------------------------
400	
401	// GetLedger returns a paginated, filtered view of distribution events.
402	func (s *DistributionService) GetLedger(filters repository.DistributionFilter, limit, offset int) ([]models.DistributionEvent, error) {
403		return s.distRepo.ListEvents(filters, limit, offset)
404	}
405	
406	// GetCustodyChain returns the full event history for a physical copy.
407	func (s *DistributionService) GetCustodyChain(scanID string) ([]models.DistributionEvent, error) {
408		if scanID == "" {
409			return nil, errors.New("service: GetCustodyChain: scanID is required")
410		}
411		return s.distRepo.GetCustodyChain(scanID)
412	}
413	
414	// GetPendingIssues returns the clerk's pick list.
415	func (s *DistributionService) GetPendingIssues(limit, offset int) ([]repository.PendingIssue, error) {
416		return s.distRepo.GetPendingIssues(limit, offset)
417	}
418	
419	// CountBackorders returns the total number of unresolved backorder records.
420	func (s *DistributionService) CountBackorders() (int, error) {
421		return s.distRepo.CountBackorders()
422	}
423	
424	// ---------------------------------------------------------------
425	// helpers
426	// ---------------------------------------------------------------
427	
428	// recordReturnInternal records the return event and releases inventory without
429	// validating a return_request. It is used internally by RecordExchange, which
430	// has already validated the exchange request before splitting into legs.
431	func (s *DistributionService) recordReturnInternal(orderID, materialID, actorID int64, scanID string, qty int) error {
432		orderIDPtr := &orderID
433		actorIDPtr := &actorID
434		scanIDPtr := &scanID
435	
