1	package handlers
2	
3	import (
4		"strconv"
5	
6		"github.com/gofiber/fiber/v2"
7	
8		"w2t86/internal/middleware"
9		"w2t86/internal/observability"
10		"w2t86/internal/services"
11	)
12	
13	// MessagingHandler serves the unified inbox, notification management,
14	// DND settings, and subscription pages.
15	type MessagingHandler struct {
16		msgService *services.MessagingService
17	}
18	
19	// NewMessagingHandler creates a MessagingHandler backed by the given service.
20	func NewMessagingHandler(ms *services.MessagingService) *MessagingHandler {
21		return &MessagingHandler{msgService: ms}
22	}
23	
24	// ---------------------------------------------------------------
25	// Inbox pages
26	// ---------------------------------------------------------------
27	
28	// Inbox handles GET /inbox — renders the full inbox page.
29	func (h *MessagingHandler) Inbox(c *fiber.Ctx) error {
30		user := middleware.GetUser(c)
31	
32		limit := 30
33		offset := 0
34		if p := c.QueryInt("page", 1); p > 1 {
35			offset = (p - 1) * limit
36		}
37	
38		notifications, err := h.msgService.GetInbox(user.ID, limit, offset)
39		if err != nil {
40			observability.App.Warn("get inbox failed", "user_id", user.ID, "error", err)
41			notifications = nil
42		}
43	
44		unread, err := h.msgService.CountUnread(user.ID)
45		if err != nil {
46			observability.App.Warn("count unread failed", "user_id", user.ID, "error", err)
47			unread = 0
48		}
49	
50		return c.Render("inbox/list", fiber.Map{
51			"Title":         "Inbox",
52			"User":          user,
53			"Notifications": notifications,
54			"UnreadCount":   unread,
55			"ActivePage":    "inbox",
56		}, "layouts/base")
57	}
58	
59	// InboxItems handles GET /inbox/items — HTMX partial for notification list
60	// (used by the 30-second auto-poll on the inbox page).
61	func (h *MessagingHandler) InboxItems(c *fiber.Ctx) error {
62		user := middleware.GetUser(c)
63	
64		limit := 30
65		offset := 0
66		if p := c.QueryInt("page", 1); p > 1 {
67			offset = (p - 1) * limit
68		}
69	
70		notifications, err := h.msgService.GetInbox(user.ID, limit, offset)
71		if err != nil {
72			observability.App.Warn("get inbox items failed", "user_id", user.ID, "error", err)
73			notifications = nil
74		}
75	
76		return c.Render("partials/inbox_items", fiber.Map{
77			"Notifications": notifications,
78			"User":          user,
79		})
80	}
81	
82	// MarkRead handles POST /inbox/:id/read — marks a single notification as read.
83	// Returns the updated badge partial via HTMX OOB swap.
84	func (h *MessagingHandler) MarkRead(c *fiber.Ctx) error {
85		user := middleware.GetUser(c)
86	
87		id, err := c.ParamsInt("id")
88		if err != nil {
89			return apiErr(c, fiber.StatusBadRequest, "Invalid notification ID")
90		}
91	
92		if err := h.msgService.MarkRead(int64(id), user.ID); err != nil {
93			observability.App.Warn("mark notification read failed", "notification_id", id, "user_id", user.ID, "error", err)
94		}
95	
96		unread, err := h.msgService.CountUnread(user.ID)
97		if err != nil {
98			observability.App.Warn("count unread failed", "user_id", user.ID, "error", err)
99			unread = 0
100		}
101		return c.Render("partials/inbox_badge", fiber.Map{
102			"Count": unread,
103		})
104	}
105	
106	// MarkAllRead handles POST /inbox/read-all — marks all notifications as read.
107	// Returns the updated badge partial.
108	func (h *MessagingHandler) MarkAllRead(c *fiber.Ctx) error {
109		user := middleware.GetUser(c)
110	
111		if err := h.msgService.MarkAllRead(user.ID); err != nil {
112			observability.App.Warn("mark all read failed", "user_id", user.ID, "error", err)
113		}
114	
115		unread, err := h.msgService.CountUnread(user.ID)
116		if err != nil {
117			observability.App.Warn("count unread failed", "user_id", user.ID, "error", err)
118			unread = 0
119		}
120		return c.Render("partials/inbox_badge", fiber.Map{
121			"Count": unread,
122		})
123	}
124	
125	// ---------------------------------------------------------------
126	// Settings page
127	// ---------------------------------------------------------------
128	
129	// Settings handles GET /inbox/settings — DND + subscription settings page.
130	func (h *MessagingHandler) Settings(c *fiber.Ctx) error {
131		user := middleware.GetUser(c)
132	
133		dnd, err := h.msgService.GetDNDSettings(user.ID)
134		if err != nil {
135			observability.App.Warn("get DND settings failed", "user_id", user.ID, "error", err)
136			dnd = nil
137		}
138		subs, err := h.msgService.GetSubscriptions(user.ID)
139		if err != nil {
140			observability.App.Warn("get subscriptions failed", "user_id", user.ID, "error", err)
141			subs = nil
142		}
143	
144		// Build a map of topic -> active for easy template lookup.
145		subMap := map[string]bool{}
146		for _, s := range subs {
147			subMap[s.Topic] = s.Active == 1
148		}
149	
150		topics := []fiber.Map{
151			{"Key": services.TopicOrders, "Label": "Orders"},
152			{"Key": services.TopicReturns, "Label": "Returns"},
153			{"Key": services.TopicDistribution, "Label": "Distribution"},
154			{"Key": services.TopicAnnouncements, "Label": "Announcements"},
155			{"Key": services.TopicModeration, "Label": "Moderation"},
156		}
157	
158		return c.Render("inbox/settings", fiber.Map{
159			"Title":      "Notification Settings",
160			"User":       user,
161			"DND":        dnd,
162			"SubMap":     subMap,
163			"Topics":     topics,
164			"ActivePage": "inbox",
165		}, "layouts/base")
166	}
167	
168	// UpdateDND handles POST /inbox/settings/dnd — saves DND hours.
169	func (h *MessagingHandler) UpdateDND(c *fiber.Ctx) error {
170		user := middleware.GetUser(c)
171	
172		startHour, err := strconv.Atoi(c.FormValue("start_hour"))
173		if err != nil {
174			return htmxErr(c, fiber.StatusBadRequest, "Invalid start hour")
175		}
176		endHour, err := strconv.Atoi(c.FormValue("end_hour"))
177		if err != nil {
178			return htmxErr(c, fiber.StatusBadRequest, "Invalid end hour")
179		}
180	
181		if err := h.msgService.UpdateDND(user.ID, startHour, endHour); err != nil {
182			return htmxErr(c, fiber.StatusUnprocessableEntity, "Could not update Do-Not-Disturb settings. Please try again.")
183		}
184	
185		if c.Get("HX-Request") == "true" {
186			return c.Render("partials/flash", fiber.Map{
187				"Message": "Do-Not-Disturb hours updated.",
188			})
189		}
190		return c.Redirect("/inbox/settings", fiber.StatusFound)
191	}
192	
193	// Subscribe handles POST /inbox/subscribe — subscribes the user to a topic.
194	func (h *MessagingHandler) Subscribe(c *fiber.Ctx) error {
195		user := middleware.GetUser(c)
196		topic := c.FormValue("topic")
197	
198		if err := h.msgService.Subscribe(user.ID, topic); err != nil {
199			return htmxErr(c, fiber.StatusUnprocessableEntity, "Could not subscribe to topic. Please try again.")
200		}
201	
202		if c.Get("HX-Request") == "true" {
203			return c.Render("partials/flash", fiber.Map{
204				"Message": "Subscribed to " + topic + ".",
205			})
206		}
207		return c.Redirect("/inbox/settings", fiber.StatusFound)
208	}
209	
210	// Unsubscribe handles POST /inbox/unsubscribe — unsubscribes the user from a topic.
211	func (h *MessagingHandler) Unsubscribe(c *fiber.Ctx) error {
212		user := middleware.GetUser(c)
213		topic := c.FormValue("topic")
214	
215		if err := h.msgService.Unsubscribe(user.ID, topic); err != nil {
216			return htmxErr(c, fiber.StatusUnprocessableEntity, "Could not unsubscribe from topic. Please try again.")
217		}
218	
219		if c.Get("HX-Request") == "true" {
220			return c.Render("partials/flash", fiber.Map{
221				"Message": "Unsubscribed from " + topic + ".",
222			})
223		}
224		return c.Redirect("/inbox/settings", fiber.StatusFound)
225	}
226	
227	// ---------------------------------------------------------------
228	// Badge (OOB partial)
229	// ---------------------------------------------------------------
230	
231	// Badge handles GET /inbox/badge — returns the unread-count badge partial.
232	// Used as an out-of-band target in HTMX responses across the app.
233	func (h *MessagingHandler) Badge(c *fiber.Ctx) error {
234		user := middleware.GetUser(c)
235		unread, err := h.msgService.CountUnread(user.ID)
236		if err != nil {
237			observability.App.Warn("count unread for badge failed", "user_id", user.ID, "error", err)
238			unread = 0
239		}
240		return c.Render("partials/inbox_badge", fiber.Map{
241			"Count": unread,
242		})
243	}
