338	// parseLedgerQuery extracts filter, pagination values from the request.
339	func parseLedgerQuery(c *fiber.Ctx) (repository.DistributionFilter, int, int, int) {
340		const pageSize = 50
341	
342		page := c.QueryInt("page", 1)
343		if page < 1 {
344			page = 1
345		}
346		offset := (page - 1) * pageSize
347	
348		filters := repository.DistributionFilter{
349			ScanID:    c.Query("scan_id"),
350			EventType: c.Query("event_type"),
351			DateFrom:  c.Query("date_from"),
352			DateTo:    c.Query("date_to"),
353		}
354	
355		if rawMID := c.Query("material_id"); rawMID != "" {
356			if mid, err := strconv.ParseInt(rawMID, 10, 64); err == nil {
357				filters.MaterialID = &mid
358			}
359		}
360		if rawAID := c.Query("actor_id"); rawAID != "" {
361			if aid, err := strconv.ParseInt(rawAID, 10, 64); err == nil {
362				filters.ActorID = &aid
363			}
364		}
365	
366		return filters, pageSize, offset, page
367	}
