682	// ConfirmPaymentWithReceipt atomically transitions an order from
683	// pending_payment → pending_shipment and inserts a financial_transaction row
684	// of type "receipt" in the same database transaction, so the audit trail is
685	// never broken. If the financial record cannot be written the status change is
686	// rolled back and the error returned.
687	func (r *OrderRepository) ConfirmPaymentWithReceipt(orderID, actorID int64) error {
688		tx, err := r.db.Begin()
689		if err != nil {
690			return fmt.Errorf("repository: ConfirmPaymentWithReceipt: begin: %w", err)
691		}
692		defer tx.Rollback() //nolint:errcheck
693	
694		// Read current status and total_amount in one query.
695		var fromStatus string
696		var totalAmount float64
697		if err := tx.QueryRow(
698			`SELECT status, total_amount FROM orders WHERE id = ?`, orderID,
699		).Scan(&fromStatus, &totalAmount); err != nil {
700			if errors.Is(err, sql.ErrNoRows) {
701				return fmt.Errorf("repository: ConfirmPaymentWithReceipt: order %d not found", orderID)
702			}
703			return fmt.Errorf("repository: ConfirmPaymentWithReceipt: load order: %w", err)
704		}
705		if fromStatus != "pending_payment" {
706			return fmt.Errorf("repository: ConfirmPaymentWithReceipt: order is %q, expected pending_payment", fromStatus)
707		}
708	
709		// Advance status to pending_shipment (auto_close_at extended by 72 h).
710		if _, err := tx.Exec(`
711			UPDATE orders
712			SET    status        = 'pending_shipment',
713			       auto_close_at = datetime('now', '+72 hours'),
714			       updated_at    = datetime('now')
715			WHERE  id = ?`, orderID); err != nil {
716			return fmt.Errorf("repository: ConfirmPaymentWithReceipt: update order: %w", err)
717		}
718	
719		// Insert order_event.
720		note := "payment confirmed"
721		if _, err := tx.Exec(`
722			INSERT INTO order_events (order_id, from_status, to_status, actor_id, note)
723			VALUES (?, 'pending_payment', 'pending_shipment', ?, ?)`,
724			orderID, actorID, note); err != nil {
725			return fmt.Errorf("repository: ConfirmPaymentWithReceipt: insert order_event: %w", err)
726		}
727	
728		// Insert the financial receipt — links the payment to the order for audit.
729		ref := fmt.Sprintf("ORDER-%d", orderID)
730		if _, err := tx.Exec(`
731			INSERT INTO financial_transactions
732			            (order_id, type, amount, status, reference, note, actor_id)
733			VALUES      (?, 'receipt', ?, 'completed', ?, 'payment received', ?)`,
734			orderID, totalAmount, ref, actorID); err != nil {
735			return fmt.Errorf("repository: ConfirmPaymentWithReceipt: insert financial_transaction: %w", err)
736		}
737	
738		return tx.Commit()
739	}
740	
741	// ---------------------------------------------------------------
742	// Auto-close (scheduler entry point)
743	// ---------------------------------------------------------------
744	
745	// CloseOverdueOrders cancels all orders whose auto_close_at has passed and
746	// whose status is pending_payment or pending_shipment. Returns the count of
747	// orders closed.
748	func (r *OrderRepository) CloseOverdueOrders(materialRepo *MaterialRepository) (int, error) {
749		const selectQ = `
750			SELECT id, status
751			FROM   orders
752			WHERE  status IN ('pending_payment', 'pending_shipment')
753			  AND  auto_close_at IS NOT NULL
754			  AND  auto_close_at < datetime('now')`
755	
756		rows, err := r.db.Query(selectQ)
757		if err != nil {
758			return 0, fmt.Errorf("repository: CloseOverdueOrders: query: %w", err)
759		}
760		type row struct {
761			id     int64
762			status string
763		}
764		var overdue []row
765		for rows.Next() {
766			var rw row
767			if err := rows.Scan(&rw.id, &rw.status); err != nil {
768				rows.Close()
769				return 0, err
770			}
771			overdue = append(overdue, rw)
772		}
773		rows.Close()
774		if err := rows.Err(); err != nil {
775			return 0, err
776		}
777	
778		closed := 0
779		for _, rw := range overdue {
780			note := "auto-closed: payment timeout"
781			if rw.status == "pending_shipment" {
782				note = "auto-closed: shipment timeout"
783			}
784			if err := r.Transition(rw.id, 0, "canceled", note, materialRepo); err != nil {
785				// Log but continue — don't abort the whole batch on a single failure.
786				continue
787			}
788			closed++
789		}
790	
791		return closed, nil
792	}
