192	// ---------------------------------------------------------------
193	// Return
194	// ---------------------------------------------------------------
195	
196	// RecordReturn records a "returned" distribution event and releases inventory
197	// (increments available_qty by qty).
198	//
199	// returnRequestID must reference an approved return_request of type "return"
200	// for orderID. The call is rejected if the request does not exist, is not yet
201	// approved, or belongs to a different order.
202	func (s *DistributionService) RecordReturn(orderID, materialID, actorID, returnRequestID int64, scanID string, qty int) error {
203		if qty <= 0 {
204			return errors.New("service: RecordReturn: qty must be positive")
205		}
206	
207		// Require an approved return request of the correct type.
208		rr, err := s.orderRepo.GetReturnRequestByID(returnRequestID)
209		if err != nil {
210			return fmt.Errorf("service: RecordReturn: load return request: %w", err)
211		}
212		if rr.Status != "approved" {
213			return fmt.Errorf("service: RecordReturn: return request %d is not approved (status=%s)", returnRequestID, rr.Status)
214		}
215		if rr.OrderID != orderID {
216			return fmt.Errorf("service: RecordReturn: return request %d belongs to order %d, not %d", returnRequestID, rr.OrderID, orderID)
217		}
218		if rr.Type != "return" {
219			return fmt.Errorf("service: RecordReturn: return request %d has wrong type %q (expected 'return')", returnRequestID, rr.Type)
220		}
221	
222		// Verify order exists.
223		if _, err := s.orderRepo.GetByID(orderID); err != nil {
224			if errors.Is(err, sql.ErrNoRows) {
225				return fmt.Errorf("service: RecordReturn: order %d not found", orderID)
226			}
227			return fmt.Errorf("service: RecordReturn: load order: %w", err)
228		}
229	
230		orderIDPtr := &orderID
231		actorIDPtr := &actorID
232		scanIDPtr := &scanID
233	
234		evt := &models.DistributionEvent{
235			OrderID:     orderIDPtr,
236			MaterialID:  materialID,
237			Qty:         qty,
238			EventType:   "returned",
239			ScanID:      scanIDPtr,
240			ActorID:     actorIDPtr,
241			CustodyFrom: stringPtr("student"),
242			CustodyTo:   stringPtr("clerk"),
243		}
244		if _, err := s.distRepo.RecordEvent(evt); err != nil {
245			return fmt.Errorf("service: RecordReturn: record event: %w", err)
246		}
247	
248		// Return copies to available stock. The order is already completed so
249		// reserved_qty for these items has already been decremented by the
250		// completion transition; we only need to increment available_qty.
251		if err := s.materialRepo.ReturnToStock(materialID, qty); err != nil {
252			return fmt.Errorf("service: RecordReturn: return to stock: %w", err)
253		}
