259	// ---------------------------------------------------------------
260	// Exchange
261	// ---------------------------------------------------------------
262	
263	// RecordExchange swaps an old copy for a new one in a single logical operation:
264	//  1. Validates the approved exchange request.
265	//  2. Records a "returned" event for oldMaterialID.
266	//  3. Verifies the new material has available stock.
267	//  4. Records an "issued" event for newMaterialID and decrements its
268	//     available_qty.
269	//
270	// returnRequestID must reference an approved return_request of type "exchange"
271	// for orderID.
272	func (s *DistributionService) RecordExchange(orderID, oldMaterialID, newMaterialID, actorID, returnRequestID int64, scanID string, qty int) error {
273		if qty <= 0 {
274			return errors.New("service: RecordExchange: qty must be positive")
275		}
276	
277		// Require an approved exchange request of the correct type.
278		rr, err := s.orderRepo.GetReturnRequestByID(returnRequestID)
279		if err != nil {
280			return fmt.Errorf("service: RecordExchange: load return request: %w", err)
281		}
282		if rr.Status != "approved" {
283			return fmt.Errorf("service: RecordExchange: return request %d is not approved (status=%s)", returnRequestID, rr.Status)
284		}
285		if rr.OrderID != orderID {
286			return fmt.Errorf("service: RecordExchange: return request %d belongs to order %d, not %d", returnRequestID, rr.OrderID, orderID)
287		}
288		if rr.Type != "exchange" {
289			return fmt.Errorf("service: RecordExchange: return request %d has wrong type %q (expected 'exchange')", returnRequestID, rr.Type)
290		}
291	
292		// Return the old copy (releases its inventory).
293		// We pass 0 as returnRequestID to the inner RecordReturn because the
294		// exchange request already covers both legs; RecordReturn's own request
295		// check is bypassed here via the internal call path.
296		if err := s.recordReturnInternal(orderID, oldMaterialID, actorID, scanID, qty); err != nil {
297			return fmt.Errorf("service: RecordExchange: return old: %w", err)
298		}
299	
300		// Check new material stock.
301		newMat, err := s.materialRepo.GetByID(newMaterialID)
302		if err != nil {
303			if errors.Is(err, sql.ErrNoRows) {
304				return fmt.Errorf("service: RecordExchange: new material %d not found", newMaterialID)
305			}
306			return fmt.Errorf("service: RecordExchange: load new material: %w", err)
307		}
308		if newMat.AvailableQty < qty {
309			return fmt.Errorf("service: RecordExchange: insufficient stock for material %q (available %d, requested %d)",
310				newMat.Title, newMat.AvailableQty, qty)
311		}
312	
313		orderIDPtr := &orderID
314		actorIDPtr := &actorID
315		newScanID := scanID + "_exch"
316		scanIDPtr := &newScanID
317	
318		evt := &models.DistributionEvent{
319			OrderID:     orderIDPtr,
320			MaterialID:  newMaterialID,
321			Qty:         qty,
322			EventType:   "issued",
323			ScanID:      scanIDPtr,
324			ActorID:     actorIDPtr,
325			CustodyFrom: stringPtr("clerk"),
326			CustodyTo:   stringPtr("student"),
327		}
328		if _, err := s.distRepo.RecordEvent(evt); err != nil {
329			return fmt.Errorf("service: RecordExchange: record issue event: %w", err)
330		}
331	
332		// Directly decrement available_qty for the newly issued material. Because
333		// the exchange is performed post-fulfillment the new copy goes straight
334		// to the student without a reservation phase, so DirectIssue (available
335		// only) is correct — Reserve would incorrectly increment reserved_qty.
336		if err := s.materialRepo.DirectIssue(newMaterialID, qty); err != nil {
337			return fmt.Errorf("service: RecordExchange: direct issue new material: %w", err)
338		}
339	
340		observability.Distribution.Info("item exchanged", "order_id", orderID, "old_material_id", oldMaterialID, "new_material_id", newMaterialID, "qty", qty, "actor_id", actorID)
341		return nil
342	}
