345	// ---------------------------------------------------------------
346	// Reissue
347	// ---------------------------------------------------------------
348	
349	// ReissueItem handles lost or damaged copy replacement:
350	//   - Validates that the material has at least one available copy for the
351	//     replacement (mirrors the availability check in RecordExchange).
352	//   - Records a "lost" or "damaged" event for oldScanID (marking it out of
353	//     circulation).
354	//   - Records a new "issued" event for newScanID.
355	//   - Decrements available_qty for the replacement copy so the inventory ledger
356	//     stays consistent with the physical state of the collection.
357	//
358	// reason must be "lost" or "damaged".
359	func (s *DistributionService) ReissueItem(orderID, materialID, actorID int64, oldScanID, newScanID, reason string) error {
360		if reason != "lost" && reason != "damaged" {
361			return fmt.Errorf("service: ReissueItem: invalid reason %q (must be 'lost' or 'damaged')", reason)
362		}
363		if oldScanID == "" || newScanID == "" {
364			return errors.New("service: ReissueItem: both oldScanID and newScanID are required")
365		}
366	
367		// Verify order exists.
368		if _, err := s.orderRepo.GetByID(orderID); err != nil {
369			if errors.Is(err, sql.ErrNoRows) {
370				return fmt.Errorf("service: ReissueItem: order %d not found", orderID)
371			}
372			return fmt.Errorf("service: ReissueItem: load order: %w", err)
373		}
374	
375		// Verify the material has at least one available copy for the replacement.
376		// A reissue takes a fresh copy from the shelf — the lost/damaged copy is
377		// already gone, so we must confirm stock before committing the event.
378		mat, err := s.materialRepo.GetByID(materialID)
379		if err != nil {
380			if errors.Is(err, sql.ErrNoRows) {
381				return fmt.Errorf("service: ReissueItem: material %d not found", materialID)
382			}
383			return fmt.Errorf("service: ReissueItem: load material: %w", err)
384		}
385		if mat.AvailableQty < 1 {
386			return fmt.Errorf("service: ReissueItem: no available stock for %q — cannot issue replacement", mat.Title)
387		}
388	
389		orderIDPtr := &orderID
390		actorIDPtr := &actorID
391	
392		// Record the loss/damage event for the old scan ID.
393		oldEvt := &models.DistributionEvent{
394			OrderID:    orderIDPtr,
395			MaterialID: materialID,
396			Qty:        1,
397			EventType:  reason, // "lost" or "damaged"
398			ScanID:     &oldScanID,
399			ActorID:    actorIDPtr,
400		}
401		if _, err := s.distRepo.RecordEvent(oldEvt); err != nil {
402			return fmt.Errorf("service: ReissueItem: record %s event: %w", reason, err)
403		}
404	
405		// Issue the replacement copy and record the event.
406		newEvt := &models.DistributionEvent{
407			OrderID:     orderIDPtr,
408			MaterialID:  materialID,
409			Qty:         1,
410			EventType:   "issued",
411			ScanID:      &newScanID,
412			ActorID:     actorIDPtr,
413			CustodyFrom: stringPtr("clerk"),
414			CustodyTo:   stringPtr("student"),
415		}
416		if _, err := s.distRepo.RecordEvent(newEvt); err != nil {
417			return fmt.Errorf("service: ReissueItem: record replacement issue event: %w", err)
418		}
419	
420		// Decrement available_qty for the replacement copy (mirrors RecordExchange).
421		// The lost/damaged copy is already out of circulation, so only the new
422		// replacement needs to leave the available pool.
423		if err := s.materialRepo.DirectIssue(materialID, 1); err != nil {
424			return fmt.Errorf("service: ReissueItem: decrement inventory for replacement: %w", err)
425		}
426	
427		observability.Distribution.Info("item reissued",
428			"order_id", orderID, "material_id", materialID,
429			"old_scan_id", oldScanID, "new_scan_id", newScanID,
430			"reason", reason, "actor_id", actorID)
431		return nil
432	}
