165	// IsInDND reports whether the current UTC hour falls within the user's DND window.
166	// Handles the wrap-around case (e.g. start=21, end=7 means 21:00–06:59 next day).
167	// When no DND row exists the default quiet-hours window 21:00–07:00 UTC is applied,
168	// ensuring new users receive protection without requiring explicit configuration.
169	// Setting start == end disables DND entirely.
170	func (r *MessagingRepository) IsInDND(userID int64) (bool, error) {
171		dnd, err := r.GetDND(userID)
172		if err != nil {
173			return false, err
174		}
175	
176		var start, end int
177		if dnd == nil {
178			// Default quiet-hours window: 21:00–07:00 UTC.
179			start, end = 21, 7
180		} else {
181			start, end = dnd.StartHour, dnd.EndHour
182		}
183	
184		// start == end means DND is disabled.
185		if start == end {
186			return false, nil
187		}
188	
189		currentHour := time.Now().UTC().Hour()
190		var inWindow bool
191		if start < end {
192			// Normal window, e.g. 09:00–17:00: current >= start AND current < end
193			inWindow = currentHour >= start && currentHour < end
194		} else {
195			// Wrap-around window, e.g. 21:00–07:00: current >= start OR current < end
196			inWindow = currentHour >= start || currentHour < end
197		}
198		return inWindow, nil
199	}
